# Tool Name: cwe_113_0_v1_tool
# Description: Stores specific pieces of information in an HTTP response header.
# Arguments: info (dict), headers (dict)
# Returns: The modified headers  (dict).
# Requires: None
def cwe_113_0_v1_tool(info, headers):
    # Define the mapping from information types to corresponding HTTP response headers
    header_mapping = {
        'lang': 'Accept-Language',
        'cache': 'Cache-Control'
    }

    for key, value in info.items():
        if key in header_mapping:
            headers[header_mapping[key]] = value

    return headers

